r.post("/api/playground/proxy", async (c) => {
  const user = c.get("user");
  const body = await c.req.json().catch(() => ({}));
  const credentialId = String(body.credential_id ?? body.credentialId ?? "");
  const method = String(body.method ?? "GET").toUpperCase();
  const endpoint = String(body.endpoint ?? "/").trim();
  const query2 = body.query && typeof body.query === "object" ? body.query : {};
  const bodyJson = body.body && typeof body.body === "object" ? body.body : {};
  if (!credentialId)
    return c.json({ error: "credential_id wajib diisi" }, 400);
  if (!["GET", "POST", "PUT", "PATCH", "DELETE"].includes(method))
    return c.json({ error: "method tidak didukung" }, 400);
  if (!endpoint.startsWith("/"))
    return c.json({ error: "endpoint harus diawali /" }, 400);
  const rows = await q(`select provider_name, credentials
       from public.provider_credentials
      where id = $1 and user_id = $2 and status = 'active'
      limit 1`, [credentialId, user.id]);
  if (!rows.length)
    return c.json({ error: "Credential tidak ditemukan/aktif" }, 404);
  const provider = String(rows[0].provider_name || "").toLowerCase();
  const cred = parseCredBlob(rows[0].credentials);
  const upstreams = config.providerUpstreams;
  const base = upstreams[provider];
  let target = "";
  const headers = {};
  if (provider === "rapidapi") {
    const host = String(cred.rapidapi_host || "").trim().replace(/^https?:\/\//, "").split("/")[0];
    const key = String(cred.api_key || "").trim();
    if (!host || !key)
      return c.json({ error: "rapidapi_host + api_key wajib" }, 400);
    const u = new URL(`https://${host}${endpoint}`);
    for (const [k, v] of Object.entries(query2))
      u.searchParams.set(k, String(v));
    target = u.toString();
    headers["X-RapidAPI-Key"] = key;
    headers["X-RapidAPI-Host"] = host;
  } else {
    if (!base)
      return c.json({ error: `Provider ${provider} belum didukung` }, 400);
    const u = new URL(endpoint, base.endsWith("/") ? base : `${base}/`);
    for (const [k, v] of Object.entries(query2))
      u.searchParams.set(k, String(v));
    target = u.toString();
    const providerApiKey = String(cred.api_key || cred.apiKey || "").trim();
    if (provider === "gemini" && providerApiKey) {
      u.searchParams.set("key", providerApiKey);
      target = u.toString();
    } else if ((provider === "groq" || provider === "huggingface") && providerApiKey) {
      headers.Authorization = `Bearer ${providerApiKey}`;
    } else if (provider === "apify") {
      const token = String(cred.api_token || cred.api_key || "").trim();
      if (token) {
        u.searchParams.set("token", token);
        target = u.toString();
      }
    } else if (DATA_PROVIDERS.has(provider)) {
      if (provider === "newsapi")
        u.searchParams.set("apiKey", String(cred.api_key || ""));
      else if (provider === "gnews")
        u.searchParams.set("token", String(cred.token || cred.api_key || ""));
      else if (provider === "mediastack")
        u.searchParams.set("access_key", String(cred.access_key || ""));
      else if (provider === "openweather")
        u.searchParams.set("appid", String(cred.appid || ""));
      else if (provider === "alphavantage")
        u.searchParams.set("apikey", String(cred.api_key || ""));
      target = u.toString();
    }
  }
  try {
    const res = await fetch(target, {
      method,
      headers: {
        "Content-Type": "application/json",
        ...headers
      },
      body: method === "GET" ? void 0 : JSON.stringify(bodyJson),
      signal: AbortSignal.timeout(12e3)
    });
    const contentType = res.headers.get("content-type") || "";
    const payload = contentType.includes("application/json") ? await res.json().catch(() => ({})) : await res.text();
    return c.json({
      ok: res.ok,
      status: res.status,
      provider,
      endpoint,
      upstream: target,
      data: payload
    }, res.ok ? 200 : 400);
  } catch (e) {
    return c.json({ error: String(e.message || e) }, 502);
  }
});
